INSERT INTO `clinics` (`id`, `name`, `address`, `descriptionMarkdown`, `descriptionHTML`, `image`, `createdAt`, `updatedAt`) VALUES
(2, 'Hệ thống Y Tế Thu Cúc', 'Cơ sở Thụy Khuê: 286, 288, 290, 292, 294 Thụy Khuê, Phường Tây Hồ, Thành phố Hà Nội. ', '\n## **GIỚI THIỆU**\n\n**Hệ thống Y tế Thu Cúc TCI tự hào là đơn vị y tế được hàng triệu người dân tin tưởng và Sở Y tế công nhận**\n\n**TOP 3 Bệnh viện tư nhân có điểm chất lượng dẫn đầu Hà Nội\n\n* TOP 5 bệnh viện có điểm chất lượng cao nhất\n\n* 99% khách hàng đánh giá hài lòng theo thang điểm chấm của Sở Y tế\n\n* Hệ thống Y tế Thu Cúc TCI quy tụ đội ngũ bác sĩ gồm đông đảo các Giáo sư, Tiến sĩ, Thạc sĩ, Bác sĩ giỏi chuyên môn và giàu kinh nghiệm.\n\n\n* Đại tá, Phó Giáo sư, Tiến sĩ, Bác sĩ chuyên khoa II, Thầy thuốc nhân dân Nguyễn Văn Quýnh: 40 năm kinh nghiệm trong chuyên khoa Tim mạch. Hơn 30 năm công tác tại Bệnh viện Trung ương Quận đội 108\n\n* Tiến sĩ, Bác sĩ Nguyễn Văn Doanh: Nguyên là chủ nhiệm khoa thần kinh, Bệnh viện Hữu Nghị\n\n\n* Tiến sĩ, Bác sĩ Nguyễn Thị Thu Hương: Nguyên Phó Giám đốc Bệnh viện Thận Hà Nội. Hơn 30 năm kinh nghiệm khám và chữa các bệnh thận, tiết niệu\n\n* Phó Giáo sư, Tiến sĩ, Bác sĩ chuyên khoa I, Thầy thuốc nhân dân Nguyễn Xuân Thành: Hơn 30 năm kinh nghiệm trong lĩnh vực gan mật.\n*\n\n* Và nhiều Phó Giáo sư, Tiến sĩ, Thạc sĩ, Bác sĩ uy tín khác.\n\n**Địa chỉ:**\n\n* Cơ sở Thụy Khuê: 286, 288, 290, 292, 294 Thụy Khuê, Phường Tây Hồ, Thành phố Hà Nội.\n\n* Cơ sở Trần Duy Hưng: 216 Trần Duy Hưng, phường Yên Hòa, Thành phố Hà Nội\n\n* Cơ sở Đại Từ: 32 Đại Từ, phường Định Công, Hà Nội\n\n**Thời gian làm việc chung:**\n\n* Nhằm đáp ứng tối đa nhu cầu thăm khám, điều trị và chăm sóc sức khỏe của đông đảo người bệnh, Hệ thống y tế Thu Cúc TCI triển khai giờ làm việc như sau:\n\n* Cơ sở 286 Thụy Khuê: Từ 7h00 – 17h00 từ Thứ 2 đến Chủ Nhật hàng tuần; Cấp cứu 24/7\n\n* Cơ sở 216 Trần Duy Hưng: Từ 7h00 - 17h00 từ Thứ 2 đến Chủ Nhật hàng tuần\n\n* Cơ sở 32 Đại Từ: Từ 7h00 - 17h00 từ Thứ 2 đến Chủ Nhật hàng tuần\n\n**Một số lưu ý**\n\n* Cơ sở 216 Trần Duy Hưng, cơ sở 32 Đại Từ, chỉ nhận khám và điều trị ngoại trú. Bệnh nhân cần cấp cứu hoặc có nhu cầu điều trị nội trú cần đến cơ sở 286 Thụy Khuê.\n\n* Hệ thống Y tế Thu Cúc TCI có tiếp nhận thanh toán viện phí qua thẻ ngân hàng, ví điện tử Momo.\n\n* Hệ thống Y tế Thu Cúc TCI có chế độ ưu tiên rõ ràng cụ thể cho các người bệnh, đảm bảo tạo thuận lợi nhất cho việc khám chữa bệnh đạt được hiệu quả. Theo đó, quy định ưu tiên người bệnh khám bệnh, chữa bệnh như sau:\n\n* Ưu tiên các trường hợp cấp cứu\n\n* Trẻ em dưới 6 tuổi, người khuyết tật nặng, người già 80 tuổi trở lên, người có công với cách mạng, phụ nữ có thai.\n\n* Người bệnh đặt hẹn (có dấu đã đặt hẹn)\n\n* Người bệnh khám các dịch vụ khác\n\n**THẾ MẠNH CHUYÊN MÔN**\n\n* Tại Hệ thống Y tế Thu Cúc TCI quy tụ đầy đủ các khoa và chuyên khoa để phục vụ tốt nhất nhu cầu khám chữa bệnh của người dân, bao gồm:\n\n\n* Khoa Phụ sản\n\n* Khoa Nội thần kinh\n\n* Khoa Ngoại mổ\n\n\n**TRANG THIẾT BỊ**\n\n* Hệ thống Y tế Thu Cúc TCI đã đầu tư những trang bị y khoa hiện đại hàng đầu ở Việt Nam. Trong đó phải kể đến hệ thống phòng mổ vô khuẩn một chiều được đánh giá là hiện đại nhất hiện nay và rất hiếm có trên cả nước. Đây là hệ thống hiện đại có khả năng khử khuẩn và lọc khí tối tân, cấp khí tươi cho phòng mổ giúp người bệnh tránh được nhiễm khuẩn trong quá trình phẫu thuật và bình phục tốt hơn trong thời gian hậu phẫu. Mỗi phòng mổ đều được trang bị hệ thống cách âm, đèn mổ, bàn mổ và các dụng cụ hỗ trợ ca mổ tiên tiến nhất của các hãng thiết bị y tế danh tiếng.\n\n\n* Cùng với đó, TCI luôn chú trọng đầu tư công nghệ, trang thiết bị y khoa hiện đại hàng đầu để đưa vào quá trình thăm khám, giúp phát hiện dấu hiệu bệnh lý dù nhỏ nhất một cách nhanh chóng nhất và chính xác nhất như:\n\n\nTán sỏi thận, sỏi tiết niệu công nghệ cao an toàn, không cần mổ và ít xâm lấn\n\n   ![img](https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc1.jpg?raw=true)\n\nNội soi tại Hệ thống Y tế Thu Cúc TCI\n\n\n![img](https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc2.jpg?raw=true)\n\nMáy chụp MRI tại Hệ thống Y tế Thu Cúc TCI\n\n\n   ![img](https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc3.jpg?raw=true)\n\nHình ảnh máy chụp CT tại Hệ thống Y tế Thu Cúc TCI\n\nVỊ TRÍ\nCác cơ sở của Hệ thống Y tế Thu Cúc TCI:\n\n1. Cơ sở 286 Thụy Khuê, Tây Hồ, Hà Nội:\n\n![img](https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc4.jpg?raw=true)\n\n**QUY TRÌNH ĐI KHÁM**\n* Dưới đây là quy trình đi khám tại Hệ thống Y tế Thu Cúc TCI dành cho bệnh nhân đăng ký qua BookingCare:\n\n* Bước 1: Sau khi đặt lịch, nhân viên của bệnh viện sẽ gọi lại để xác nhận lịch và hướng dẫn chi tiết.\n\n* Bước 2: Bạn đến bệnh viện, vào quầy lễ tân để báo đã đặt lịch để làm thủ tục thăm khám (xuất trình thẻ BHYT nếu có). Bạn sẽ được đội ngũ lễ tân, nhân viên y tế tiếp đón và hướng dẫn làm các thủ tục thăm khám cũng như hỗ trợ, giải đáp và tư vấn về các chế độ ưu đãi liên quan (bảo hiểm y tế, thẻ thành viên…).\n\n* Bước 3: Bạn vào thăm khám lâm sàng với bác sĩ chuyên khoa. Nếu gặp vấn đề về sức khỏe, bác sĩ sẽ chỉ định những xét nghiệm cũng như các phương pháp điều trị cần thiết.\n\n* Bước 4: Bạn ra quầy lễ tân thanh toán phí xét nghiệm và điều trị bệnh. Các mục thanh toán được ghi chi tiết, rõ ràng trên hóa đơn. Tại đây nhân viên thu ngân sẽ thanh toán phí bảo hiểm y tế (nếu có) theo các danh mục khám chữa bệnh bác sĩ chỉ định theo đúng quy định của Nhà nước.\n\n* Bước 5: Bạn đến phòng ban chức năng để tiến hành thăm khám và điều trị bệnh.\n\n\n', '<h2><strong>GIỚI THIỆU</strong></h2>\n<p><strong>Hệ thống Y tế Thu Cúc TCI tự hào là đơn vị y tế được hàng triệu người dân tin tưởng và Sở Y tế công nhận</strong></p>\n<p>**TOP 3 Bệnh viện tư nhân có điểm chất lượng dẫn đầu Hà Nội</p>\n<ul>\n<li>\n<p>TOP 5 bệnh viện có điểm chất lượng cao nhất</p>\n</li>\n<li>\n<p>99% khách hàng đánh giá hài lòng theo thang điểm chấm của Sở Y tế</p>\n</li>\n<li>\n<p>Hệ thống Y tế Thu Cúc TCI quy tụ đội ngũ bác sĩ gồm đông đảo các Giáo sư, Tiến sĩ, Thạc sĩ, Bác sĩ giỏi chuyên môn và giàu kinh nghiệm.</p>\n</li>\n<li>\n<p>Đại tá, Phó Giáo sư, Tiến sĩ, Bác sĩ chuyên khoa II, Thầy thuốc nhân dân Nguyễn Văn Quýnh: 40 năm kinh nghiệm trong chuyên khoa Tim mạch. Hơn 30 năm công tác tại Bệnh viện Trung ương Quận đội 108</p>\n</li>\n<li>\n<p>Tiến sĩ, Bác sĩ Nguyễn Văn Doanh: Nguyên là chủ nhiệm khoa thần kinh, Bệnh viện Hữu Nghị</p>\n</li>\n<li>\n<p>Tiến sĩ, Bác sĩ Nguyễn Thị Thu Hương: Nguyên Phó Giám đốc Bệnh viện Thận Hà Nội. Hơn 30 năm kinh nghiệm khám và chữa các bệnh thận, tiết niệu</p>\n</li>\n<li>\n<p>Phó Giáo sư, Tiến sĩ, Bác sĩ chuyên khoa I, Thầy thuốc nhân dân Nguyễn Xuân Thành: Hơn 30 năm kinh nghiệm trong lĩnh vực gan mật.</p>\n</li>\n<li></li>\n<li>\n<p>Và nhiều Phó Giáo sư, Tiến sĩ, Thạc sĩ, Bác sĩ uy tín khác.</p>\n</li>\n</ul>\n<p><strong>Địa chỉ:</strong></p>\n<ul>\n<li>\n<p>Cơ sở Thụy Khuê: 286, 288, 290, 292, 294 Thụy Khuê, Phường Tây Hồ, Thành phố Hà Nội.</p>\n</li>\n<li>\n<p>Cơ sở Trần Duy Hưng: 216 Trần Duy Hưng, phường Yên Hòa, Thành phố Hà Nội</p>\n</li>\n<li>\n<p>Cơ sở Đại Từ: 32 Đại Từ, phường Định Công, Hà Nội</p>\n</li>\n</ul>\n<p><strong>Thời gian làm việc chung:</strong></p>\n<ul>\n<li>\n<p>Nhằm đáp ứng tối đa nhu cầu thăm khám, điều trị và chăm sóc sức khỏe của đông đảo người bệnh, Hệ thống y tế Thu Cúc TCI triển khai giờ làm việc như sau:</p>\n</li>\n<li>\n<p>Cơ sở 286 Thụy Khuê: Từ 7h00 – 17h00 từ Thứ 2 đến Chủ Nhật hàng tuần; Cấp cứu 24/7</p>\n</li>\n<li>\n<p>Cơ sở 216 Trần Duy Hưng: Từ 7h00 - 17h00 từ Thứ 2 đến Chủ Nhật hàng tuần</p>\n</li>\n<li>\n<p>Cơ sở 32 Đại Từ: Từ 7h00 - 17h00 từ Thứ 2 đến Chủ Nhật hàng tuần</p>\n</li>\n</ul>\n<p><strong>Một số lưu ý</strong></p>\n<ul>\n<li>\n<p>Cơ sở 216 Trần Duy Hưng, cơ sở 32 Đại Từ, chỉ nhận khám và điều trị ngoại trú. Bệnh nhân cần cấp cứu hoặc có nhu cầu điều trị nội trú cần đến cơ sở 286 Thụy Khuê.</p>\n</li>\n<li>\n<p>Hệ thống Y tế Thu Cúc TCI có tiếp nhận thanh toán viện phí qua thẻ ngân hàng, ví điện tử Momo.</p>\n</li>\n<li>\n<p>Hệ thống Y tế Thu Cúc TCI có chế độ ưu tiên rõ ràng cụ thể cho các người bệnh, đảm bảo tạo thuận lợi nhất cho việc khám chữa bệnh đạt được hiệu quả. Theo đó, quy định ưu tiên người bệnh khám bệnh, chữa bệnh như sau:</p>\n</li>\n<li>\n<p>Ưu tiên các trường hợp cấp cứu</p>\n</li>\n<li>\n<p>Trẻ em dưới 6 tuổi, người khuyết tật nặng, người già 80 tuổi trở lên, người có công với cách mạng, phụ nữ có thai.</p>\n</li>\n<li>\n<p>Người bệnh đặt hẹn (có dấu đã đặt hẹn)</p>\n</li>\n<li>\n<p>Người bệnh khám các dịch vụ khác</p>\n</li>\n</ul>\n<p><strong>THẾ MẠNH CHUYÊN MÔN</strong></p>\n<ul>\n<li>\n<p>Tại Hệ thống Y tế Thu Cúc TCI quy tụ đầy đủ các khoa và chuyên khoa để phục vụ tốt nhất nhu cầu khám chữa bệnh của người dân, bao gồm:</p>\n</li>\n<li>\n<p>Khoa Phụ sản</p>\n</li>\n<li>\n<p>Khoa Nội thần kinh</p>\n</li>\n<li>\n<p>Khoa Ngoại mổ</p>\n</li>\n</ul>\n<p><strong>TRANG THIẾT BỊ</strong></p>\n<ul>\n<li>\n<p>Hệ thống Y tế Thu Cúc TCI đã đầu tư những trang bị y khoa hiện đại hàng đầu ở Việt Nam. Trong đó phải kể đến hệ thống phòng mổ vô khuẩn một chiều được đánh giá là hiện đại nhất hiện nay và rất hiếm có trên cả nước. Đây là hệ thống hiện đại có khả năng khử khuẩn và lọc khí tối tân, cấp khí tươi cho phòng mổ giúp người bệnh tránh được nhiễm khuẩn trong quá trình phẫu thuật và bình phục tốt hơn trong thời gian hậu phẫu. Mỗi phòng mổ đều được trang bị hệ thống cách âm, đèn mổ, bàn mổ và các dụng cụ hỗ trợ ca mổ tiên tiến nhất của các hãng thiết bị y tế danh tiếng.</p>\n</li>\n<li>\n<p>Cùng với đó, TCI luôn chú trọng đầu tư công nghệ, trang thiết bị y khoa hiện đại hàng đầu để đưa vào quá trình thăm khám, giúp phát hiện dấu hiệu bệnh lý dù nhỏ nhất một cách nhanh chóng nhất và chính xác nhất như:</p>\n</li>\n</ul>\n<p>Tán sỏi thận, sỏi tiết niệu công nghệ cao an toàn, không cần mổ và ít xâm lấn</p>\n<p><img src=\"https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc1.jpg?raw=true\" alt=\"img\"></p>\n<p>Nội soi tại Hệ thống Y tế Thu Cúc TCI</p>\n<p><img src=\"https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc2.jpg?raw=true\" alt=\"img\"></p>\n<p>Máy chụp MRI tại Hệ thống Y tế Thu Cúc TCI</p>\n<p><img src=\"https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc3.jpg?raw=true\" alt=\"img\"></p>\n<p>Hình ảnh máy chụp CT tại Hệ thống Y tế Thu Cúc TCI</p>\n<p>VỊ TRÍ\nCác cơ sở của Hệ thống Y tế Thu Cúc TCI:</p>\n<ol>\n<li>Cơ sở 286 Thụy Khuê, Tây Hồ, Hà Nội:</li>\n</ol>\n<p><img src=\"https://github.com/GDRAGON-CN/BOOKINGCARE/blob/master/src/assets/ThuCuc4.jpg?raw=true\" alt=\"img\"></p>\n<p><strong>QUY TRÌNH ĐI KHÁM</strong></p>\n<ul>\n<li>\n<p>Dưới đây là quy trình đi khám tại Hệ thống Y tế Thu Cúc TCI dành cho bệnh nhân đăng ký qua BookingCare:</p>\n</li>\n<li>\n<p>Bước 1: Sau khi đặt lịch, nhân viên của bệnh viện sẽ gọi lại để xác nhận lịch và hướng dẫn chi tiết.</p>\n</li>\n<li>\n<p>Bước 2: Bạn đến bệnh viện, vào quầy lễ tân để báo đã đặt lịch để làm thủ tục thăm khám (xuất trình thẻ BHYT nếu có). Bạn sẽ được đội ngũ lễ tân, nhân viên y tế tiếp đón và hướng dẫn làm các thủ tục thăm khám cũng như hỗ trợ, giải đáp và tư vấn về các chế độ ưu đãi liên quan (bảo hiểm y tế, thẻ thành viên…).</p>\n</li>\n<li>\n<p>Bước 3: Bạn vào thăm khám lâm sàng với bác sĩ chuyên khoa. Nếu gặp vấn đề về sức khỏe, bác sĩ sẽ chỉ định những xét nghiệm cũng như các phương pháp điều trị cần thiết.</p>\n</li>\n<li>\n<p>Bước 4: Bạn ra quầy lễ tân thanh toán phí xét nghiệm và điều trị bệnh. Các mục thanh toán được ghi chi tiết, rõ ràng trên hóa đơn. Tại đây nhân viên thu ngân sẽ thanh toán phí bảo hiểm y tế (nếu có) theo các danh mục khám chữa bệnh bác sĩ chỉ định theo đúng quy định của Nhà nước.</p>\n</li>\n<li>\n<p>Bước 5: Bạn đến phòng ban chức năng để tiến hành thăm khám và điều trị bệnh.</p>\n</li>\n</ul>\n', , '2026-04-02 05:30:46', '2026-04-05 16:07:58');

