CREATE TABLE `specialties` (
  `id` int(11) NOT NULL,
  `name` varchar(255) DEFAULT NULL,
  `descriptionHTML` text DEFAULT NULL,
  `descriptionMarkdown` text DEFAULT NULL,
  `image` longblob DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Đang đổ dữ liệu cho bảng `specialties`
--

INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(1, 'Cư Xương Khớp', '<h2><strong>Cơ Xương Khớp</strong></h2>\n<p><strong>Bác sĩ Cơ Xương Khớp giỏi</strong></p>\n<p>Danh sách các bác sĩ uy tín đầu ngành Cơ Xương Khớp tại Việt Nam:</p>\n<ul>\n<li>Các chuyên gia có quá trình đào tạo bài bản, nhiều kinh nghiệm</li>\n<li>Các giáo sư, phó giáo sư đang trực tiếp nghiên cứu và giảng dạy tại Đại học Y khoa Hà Nội</li>\n<li>Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu Khoa Cơ Xương Khớp - Bệnh viện Bạch Mai, Bệnh viện Hữu nghị Việt Đức,Bệnh Viện E.</li>\n<li>Là thành viên hoặc lãnh đạo các tổ chức chuyên môn như: Hiệp hội Cơ Xương Khớp, Hội Thấp khớp học,...</li>\n<li>Được nhà nước công nhận các danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ Cao cấp,...</li>\n</ul>\n<p><strong>Bệnh Cơ Xương Khớp</strong></p>\n<ul>\n<li>Gout</li>\n<li>Thoái hóa khớp: khớp gối, cột sống thắt lưng, cột sống cổ</li>\n<li>Viêm khớp dạng thấp, Viêm đa khớp, Viêm gân</li>\n<li>Tràn dịch khớp gối, Tràn dịch khớp háng, Tràn dịch khớp khủy, Tràn dịch khớp vai</li>\n<li>Loãng xương, đau nhức xương</li>\n<li>Viêm xương, gai xương</li>\n<li>Viêm cơ, Teo cơ, chứng đau mỏi cơ</li>\n<li>Yếu cơ, Loạn dưỡng cơ</li>\n<li>Các chấn thương về cơ, xương, khớp</li>\n</ul>\n', '\n\n\n## **Cơ Xương Khớp**\n\n\n **Bác sĩ Cơ Xương Khớp giỏi**\n\nDanh sách các bác sĩ uy tín đầu ngành Cơ Xương Khớp tại Việt Nam:\n\n- Các chuyên gia có quá trình đào tạo bài bản, nhiều kinh nghiệm\n- Các giáo sư, phó giáo sư đang trực tiếp nghiên cứu và giảng dạy tại Đại học Y khoa Hà Nội\n- Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu Khoa Cơ Xương Khớp - Bệnh viện Bạch Mai, Bệnh viện Hữu nghị Việt Đức,Bệnh Viện E.\n- Là thành viên hoặc lãnh đạo các tổ chức chuyên môn như: Hiệp hội Cơ Xương Khớp, Hội Thấp khớp học,...\n- Được nhà nước công nhận các danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ Cao cấp,...\n\n **Bệnh Cơ Xương Khớp**\n\n- Gout\n- Thoái hóa khớp: khớp gối, cột sống thắt lưng, cột sống cổ\n- Viêm khớp dạng thấp, Viêm đa khớp, Viêm gân\n- Tràn dịch khớp gối, Tràn dịch khớp háng, Tràn dịch khớp khủy, Tràn dịch khớp vai\n- Loãng xương, đau nhức xương\n- Viêm xương, gai xương\n- Viêm cơ, Teo cơ, chứng đau mỏi cơ\n- Yếu cơ, Loạn dưỡng cơ\n- Các chấn thương về cơ, xương, khớp', , '2026-04-02 04:48:46', '2026-04-02 04:48:46');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(2, 'Thần Kinh', '<h2><strong>Thần kinh</strong></h2>\n<p><strong>Bác sĩ Thần kinh giỏi</strong></p>\n<p>Danh sách các giáo sư, bác sĩ chuyên khoa Thần kinh giỏi:</p>\n<ul>\n<li>Các giáo sư, bác sĩ uy tín đầu ngành chuyên khoa Thần kinh đã và đang công tác tại các bệnh viện lớn như: Bệnh viện Bạch Mai, Bệnh viện Việt Đức, Bệnh viện 108, Bệnh viện Đại học Y Hà Nội, Bệnh viện 103.</li>\n<li>Là thành viên hoặc lãnh đạo các tổ chức chuyên môn như: Hội Thần kinh Việt Nam, Hội Phẫu thuật Thần kinh...</li>\n<li>Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp.</li>\n</ul>\n<p><strong>Khám bệnh chuyên khoa Thần kinh</strong></p>\n<ul>\n<li>Bại Não</li>\n<li>Đau đầu, chóng mặt, buồn nôn</li>\n<li>Bệnh Pakison, bệnh tiền đình</li>\n<li>Bị co cơ, căng dây thần kinh</li>\n<li>Động kinh, có những cơn vãng ý thức</li>\n<li>Bị tê bì nửa mặt, chèn dây thần kinh</li>\n<li>Bồn chồn, lo lắng, hồi hộp, chân tay run</li>\n<li>Có dấu hiệu tăng động</li>\n<li>Co rút cổ, đau đầu với mặt, chân tay, vã mồ hôi</li>\n<li>Chấn thương đầu, dây thần kinh</li>\n</ul>\n', '\n## **Thần kinh**\n\n\n**Bác sĩ Thần kinh giỏi**\n\nDanh sách các giáo sư, bác sĩ chuyên khoa Thần kinh giỏi:\n\n- Các giáo sư, bác sĩ uy tín đầu ngành chuyên khoa Thần kinh đã và đang công tác tại các bệnh viện lớn như: Bệnh viện Bạch Mai, Bệnh viện Việt Đức, Bệnh viện 108, Bệnh viện Đại học Y Hà Nội, Bệnh viện 103.\n- Là thành viên hoặc lãnh đạo các tổ chức chuyên môn như: Hội Thần kinh Việt Nam, Hội Phẫu thuật Thần kinh...\n- Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp.\n\n **Khám bệnh chuyên khoa Thần kinh**\n\n- Bại Não\n- Đau đầu, chóng mặt, buồn nôn\n- Bệnh Pakison, bệnh tiền đình\n- Bị co cơ, căng dây thần kinh\n- Động kinh, có những cơn vãng ý thức\n- Bị tê bì nửa mặt, chèn dây thần kinh\n- Bồn chồn, lo lắng, hồi hộp, chân tay run\n- Có dấu hiệu tăng động\n- Co rút cổ, đau đầu với mặt, chân tay, vã mồ hôi\n- Chấn thương đầu, dây thần kinh\n', , '2026-04-02 04:51:01', '2026-04-02 04:51:01');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(3, 'Tiêu Hóa', '<h2><strong>Tiêu hóa</strong></h2>\n<p><strong>Bác sĩ Chuyên khoa Tiêu hóa</strong></p>\n<p>Danh sách các bác sĩ Tiêu hóa uy tín đầu ngành tại Việt Nam:</p>\n<ul>\n<li>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên ngành Tiêu hóa tại Hà Nội</li>\n<li>Các giáo sư, phó giáo sư là giảng viên Đại học Y khoa Hà Nội</li>\n<li>Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như Bệnh viện Bạch Mai, Bệnh Viện Việt Đức, Bệnh Viện Nhi Trung ương, Bệnh viện Y học Cổ truyền Việt Nam...</li>\n<li>Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp,...</li>\n</ul>\n<p><strong>Tư vấn, khám và điều trị các Bệnh Tiêu hóa</strong></p>\n<ul>\n<li>Ăn uống kém, không ngon</li>\n<li>Rối loạn tiêu hóa, táo bón, trĩ</li>\n<li>Nhiễm vi khuẩn HP (Helicobacter pylori)</li>\n<li>Nội soi dạ dày, đại tràng, tiêu hóa</li>\n<li>Buồn nôn, chướng bụng, đầy bụng ợ chua, đầy hơi</li>\n<li>Co thắt thực quản, Hội chứng ruột kích thích</li>\n<li>Đau bụng, dạ dày, đại tràng, thượng vị</li>\n<li>Viêm đại tràng, dạ dày, tá tràng</li>\n<li>Ung thư dạ dày, U nang tuyến tụy</li>\n<li>Bệnh lý về gan, mật</li>\n</ul>\n', '\n## **Tiêu hóa**\n\n\n**Bác sĩ Chuyên khoa Tiêu hóa**\n\nDanh sách các bác sĩ Tiêu hóa uy tín đầu ngành tại Việt Nam:\n\n- Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên ngành Tiêu hóa tại Hà Nội\n- Các giáo sư, phó giáo sư là giảng viên Đại học Y khoa Hà Nội\n- Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như Bệnh viện Bạch Mai, Bệnh Viện Việt Đức, Bệnh Viện Nhi Trung ương, Bệnh viện Y học Cổ truyền Việt Nam...\n- Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp,...\n\n**Tư vấn, khám và điều trị các Bệnh Tiêu hóa**\n\n- Ăn uống kém, không ngon\n- Rối loạn tiêu hóa, táo bón, trĩ\n- Nhiễm vi khuẩn HP (Helicobacter pylori)\n- Nội soi dạ dày, đại tràng, tiêu hóa\n- Buồn nôn, chướng bụng, đầy bụng ợ chua, đầy hơi\n- Co thắt thực quản, Hội chứng ruột kích thích\n- Đau bụng, dạ dày, đại tràng, thượng vị\n- Viêm đại tràng, dạ dày, tá tràng\n- Ung thư dạ dày, U nang tuyến tụy\n- Bệnh lý về gan, mật', , '2026-04-02 04:51:31', '2026-04-02 04:51:31');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(4, 'Tim Mạch', '<h2><strong>Tim mạch</strong></h2>\n<p><strong>Bác sĩ tim mạch giỏi</strong></p>\n<p>Danh dách các bác sĩ tim mạch uy tín đầu ngành tại Việt Nam:</p>\n<ul>\n<li>Các chuyên gia được đào tạo bài bản về chuyên ngành Tim mạch tại các trường đại học trong nước và quốc tế.</li>\n<li>Các giáo sư, phó giáo sư nghiên cứu và giảng dạy tại Đại học Y Hà Nội</li>\n<li>Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như Viện Tim Mạch Quốc Gia, Bệnh viện Bạch Mai, Bệnh viện Việt Đức, Bệnh Viện E, Bệnh Viện Tim Hà Nội</li>\n<li>Là thành viên hoặc lãnh đạo các tổ chức chuyên môn như: Hiệp hội Tim Mạch Việt Nam</li>\n<li>Đạt danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ Cao cấp,...</li>\n</ul>\n<p><strong>Khám tư vấn tim mạch</strong></p>\n<ul>\n<li>Khó thở, Đau ngực, đau tim</li>\n<li>Tăng huyết áp, hạ huyết áp</li>\n<li>Rối loạn mỡ máu, cao huyết áp, chóng mặt</li>\n<li>Bệnh van tim (Hẹp hở van tim), Hẹp động mạch chủ</li>\n<li>Cảm giác hồi hộp, tim đập nhanh</li>\n<li>Tim bẩm sinh, có tiền sử bệnh tim to, tiền sử tai biến</li>\n<li>Đã đặt stent tim, nong động mạch vành</li>\n<li>Giãn tĩnh mạch chân</li>\n</ul>\n', '\n## **Tim mạch**\n\n\n**Bác sĩ tim mạch giỏi**\n\nDanh dách các bác sĩ tim mạch uy tín đầu ngành tại Việt Nam:\n\n- Các chuyên gia được đào tạo bài bản về chuyên ngành Tim mạch tại các trường đại học trong nước và quốc tế.\n- Các giáo sư, phó giáo sư nghiên cứu và giảng dạy tại Đại học Y Hà Nội\n- Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như Viện Tim Mạch Quốc Gia, Bệnh viện Bạch Mai, Bệnh viện Việt Đức, Bệnh Viện E, Bệnh Viện Tim Hà Nội\n- Là thành viên hoặc lãnh đạo các tổ chức chuyên môn như: Hiệp hội Tim Mạch Việt Nam\n- Đạt danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ Cao cấp,...\n\n**Khám tư vấn tim mạch**\n\n- Khó thở, Đau ngực, đau tim\n- Tăng huyết áp, hạ huyết áp\n- Rối loạn mỡ máu, cao huyết áp, chóng mặt\n- Bệnh van tim (Hẹp hở van tim), Hẹp động mạch chủ\n- Cảm giác hồi hộp, tim đập nhanh\n- Tim bẩm sinh, có tiền sử bệnh tim to, tiền sử tai biến\n- Đã đặt stent tim, nong động mạch vành\n- Giãn tĩnh mạch chân', , '2026-04-02 04:52:27', '2026-04-02 05:01:05');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(7, 'Tai Mũi Họng', '<h2><strong>Tai Mũi Họng</strong></h2>\n<p><strong>Bác sĩ Chuyên khoa Tai Mũi Họng</strong></p>\n<p><strong>Danh sách các bác sĩ uy tín đầu ngành tại Việt Nam:</strong></p>\n<ul>\n<li>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên ngành Tai Mũi Họng tại Hà Nội</li>\n<li>Các giáo sư, phó giáo sư là giảng viên Đại học Y khoa Hà Nội</li>\n<li>Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như Bệnh viện Bạch Mai, Bệnh Viện Tai Mũi Họng Trung ương, Bệnh viện Quân Y 108...</li>\n<li>Được nhà nước công nhận các danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ cao cấp,...</li>\n</ul>\n<p><strong>Các bệnh Tai Mũi Họng</strong></p>\n<ul>\n<li>Ù tai, đau tai, chảy máu tai</li>\n<li>Thủng màng nhĩ, điếc đột ngột</li>\n<li>Viêm tai giữa</li>\n<li>Amidan, V.A</li>\n<li>Viêm xoang</li>\n<li>Nghẹt mũi</li>\n<li>Hay bị chảy máu cam</li>\n<li>Đau cổ họng, khó nuốt</li>\n<li>Ho kéo dài</li>\n<li>Ngủ ngáy</li>\n</ul>\n', '\n## **Tai Mũi Họng**\n\n\n**Bác sĩ Chuyên khoa Tai Mũi Họng**\n\n**Danh sách các bác sĩ uy tín đầu ngành tại Việt Nam:**\n\n- Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên ngành Tai Mũi Họng tại Hà Nội\n- Các giáo sư, phó giáo sư là giảng viên Đại học Y khoa Hà Nội\n- Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như Bệnh viện Bạch Mai, Bệnh Viện Tai Mũi Họng Trung ương, Bệnh viện Quân Y 108...\n- Được nhà nước công nhận các danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ cao cấp,...\n\n**Các bệnh Tai Mũi Họng**\n\n- Ù tai, đau tai, chảy máu tai\n- Thủng màng nhĩ, điếc đột ngột\n- Viêm tai giữa\n- Amidan, V.A\n- Viêm xoang\n- Nghẹt mũi\n- Hay bị chảy máu cam\n- Đau cổ họng, khó nuốt\n- Ho kéo dài\n- Ngủ ngáy\n', , '2026-04-02 05:01:36', '2026-04-02 05:01:36');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(9, 'Cột Sống', '<h2><strong>Cột sống</strong></h2>\n<p><strong>Bác sĩ Chuyên khoa Cột sống</strong></p>\n<p><strong>Danh sách các bác sĩ Cột sống uy tín đầu ngành tại Việt Nam.</strong></p>\n<ul>\n<li>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên khoa Thần kinh - Cột sống - Xương khớp tại Hà Nội</li>\n<li>Các giáo sư, tiến sĩ, bác sĩ là giảng viên Đại học Y khoa Hà Nội, Học viện Quân Y.</li>\n<li>Các bác sĩ đã, đang công tác tại chuyên Khoa Thần Kinh, Cột sống, Xương Khớp - Bệnh viện Bạch Mai, Bệnh Viện Việt Đức, Bệnh Viện Trung ương Quân đội 108, Bệnh viện 103...</li>\n<li>Được nhà nước công nhận các danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ Cao cấp,...</li>\n</ul>\n<p><strong>Bệnh Thần kinh - Cột sống</strong></p>\n<ul>\n<li>Đau cột sống, đau thắt lưng</li>\n<li>Chấn thương cột sống</li>\n<li>Cột sống bị đau, sưng, cong, vẹo</li>\n<li>Đau mỏi cổ vai gáy, bả vai</li>\n<li>Đau tê mông xuống chân</li>\n<li>Phồng đĩa đệm</li>\n<li>Tê bì tay chân</li>\n<li>Thóa hóa đốt sống</li>\n<li>Thoái hóa L4, L5</li>\n<li>Thoát vị đĩa đệm</li>\n<li>Vôi hóa cột sống</li>\n<li>Xẹp cột sống</li>\n</ul>\n', '\n## **Cột sống**\n\n **Bác sĩ Chuyên khoa Cột sống**\n\n**Danh sách các bác sĩ Cột sống uy tín đầu ngành tại Việt Nam.**\n\n- Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên khoa Thần kinh - Cột sống - Xương khớp tại Hà Nội\n- Các giáo sư, tiến sĩ, bác sĩ là giảng viên Đại học Y khoa Hà Nội, Học viện Quân Y.\n- Các bác sĩ đã, đang công tác tại chuyên Khoa Thần Kinh, Cột sống, Xương Khớp - Bệnh viện Bạch Mai, Bệnh Viện Việt Đức, Bệnh Viện Trung ương Quân đội 108, Bệnh viện 103...\n- Được nhà nước công nhận các danh hiệu Thầy thuốc Nhân dân, Thầy thuốc Ưu tú, Bác sĩ Cao cấp,...\n\n**Bệnh Thần kinh - Cột sống**\n\n- Đau cột sống, đau thắt lưng\n- Chấn thương cột sống\n- Cột sống bị đau, sưng, cong, vẹo\n- Đau mỏi cổ vai gáy, bả vai\n- Đau tê mông xuống chân\n- Phồng đĩa đệm\n- Tê bì tay chân\n- Thóa hóa đốt sống\n- Thoái hóa L4, L5\n- Thoát vị đĩa đệm\n- Vôi hóa cột sống\n- Xẹp cột sống', , '2026-04-02 05:02:38', '2026-04-02 05:03:12');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(12, 'Y Học Cổ truyền', '<h2>Y học Cổ truyền</h2>\n<p><strong>Bác sĩ Y học Cổ truyền giỏi</strong></p>\n<p><strong>Danh sách các bác sĩ Y học Cổ truyền uy tín đầu ngành tại Việt Nam:</strong></p>\n<ul>\n<li>\n<p>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên khoa Y học Cổ truyền</p>\n</li>\n<li>\n<p>Các bác sĩ đã, đang công tác tại chuyên Khoa Y học Cổ truyền - Bệnh viện Y học Cổ truyền Trung ương, Bệnh viện Bạch Mai, Thanh Nhàn..</p>\n</li>\n<li>\n<p>Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp,..</p>\n</li>\n</ul>\n<p><strong>Tư vấn, khám và điều trị các vấn đề:</strong></p>\n<ul>\n<li>\n<p>Bệnh lý thần kinh: đau đầu, mất ngủ, suy nhược thần kinh...</p>\n</li>\n<li>\n<p>Bệnh lý cơ xương khớp: đau mỏi tay chân, thoái hóa khớp, viêm khớp...</p>\n</li>\n<li>\n<p>Bệnh lý tim mạch: Tăng huyết áp, huyết áp thấp, đau thắt ngực...</p>\n</li>\n<li>\n<p>Bệnh lý đường tiêu hóa: đau bụng, rối loạn chức năng tiêu hóa...</p>\n</li>\n</ul>\n', '\n## Y học Cổ truyền\n\n\n**Bác sĩ Y học Cổ truyền giỏi**\n\n**Danh sách các bác sĩ Y học Cổ truyền uy tín đầu ngành tại Việt Nam:**\n\n* Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên khoa Y học Cổ truyền\n\n* Các bác sĩ đã, đang công tác tại chuyên Khoa Y học Cổ truyền - Bệnh viện Y học Cổ truyền Trung ương, Bệnh viện Bạch Mai, Thanh Nhàn..\n\n* Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp,..\n\n**Tư vấn, khám và điều trị các vấn đề:**\n\n\n* Bệnh lý thần kinh: đau đầu, mất ngủ, suy nhược thần kinh...\n\n* Bệnh lý cơ xương khớp: đau mỏi tay chân, thoái hóa khớp, viêm khớp...\n\n* Bệnh lý tim mạch: Tăng huyết áp, huyết áp thấp, đau thắt ngực...\n\n* Bệnh lý đường tiêu hóa: đau bụng, rối loạn chức năng tiêu hóa...', , '2026-04-05 15:08:59', '2026-04-05 15:08:59');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(14, 'Châm cứu', '<h2>Châm cứu</h2>\n<p><strong>Bác sĩ Châm cứu giỏi</strong></p>\n<p><strong>Bác sĩ Y học Cổ truyền uy tín đầu ngành tại Việt Nam:</strong></p>\n<ul>\n<li>\n<p>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên khoa Y học Cổ truyền</p>\n</li>\n<li>\n<p>Các bác sĩ đã, đang công tác tại chuyên Khoa Y học Cổ truyền - Bệnh viện Y học Cổ truyền Trung ương, Bệnh viện Bạch Mai, Thanh Nhàn..</p>\n</li>\n<li>\n<p>Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp,..</p>\n</li>\n</ul>\n<p><strong>Tư vấn, khám và điều trị các vấn đề:</strong></p>\n<ul>\n<li>\n<p>Bệnh lý thần kinh: đau đầu, mất ngủ, suy nhược thần kinh...</p>\n</li>\n<li>\n<p>Bệnh lý cơ xương khớp: đau mỏi tay chân, thoái hóa khớp, viêm khớp...</p>\n</li>\n<li>\n<p>Bệnh lý tim mạch: Tăng huyết áp, huyết áp thấp, đau thắt ngực...</p>\n</li>\n<li>\n<p>Bệnh lý đường tiêu hóa: đau bụng, rối loạn chức năng tiêu hóa</p>\n</li>\n</ul>\n', '\n## Châm cứu\n\n**Bác sĩ Châm cứu giỏi**\n\n**Bác sĩ Y học Cổ truyền uy tín đầu ngành tại Việt Nam:**\n\n* Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên khoa Y học Cổ truyền\n\n* Các bác sĩ đã, đang công tác tại chuyên Khoa Y học Cổ truyền - Bệnh viện Y học Cổ truyền Trung ương, Bệnh viện Bạch Mai, Thanh Nhàn..\n\n* Được nhà nước công nhận các danh hiệu Thầy thuốc nhân dân, thầy thuốc ưu tú, bác sĩ cao cấp,..\n\n**Tư vấn, khám và điều trị các vấn đề:**\n\n* Bệnh lý thần kinh: đau đầu, mất ngủ, suy nhược thần kinh...\n\n* Bệnh lý cơ xương khớp: đau mỏi tay chân, thoái hóa khớp, viêm khớp...\n\n* Bệnh lý tim mạch: Tăng huyết áp, huyết áp thấp, đau thắt ngực...\n\n* Bệnh lý đường tiêu hóa: đau bụng, rối loạn chức năng tiêu hóa', , '2026-04-05 15:11:16', '2026-04-05 15:11:16');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(16, 'Sản Phụ Khoa', '<h2>Sản Phụ khoa</h2>\n<p><strong>Bác sĩ Sản phụ khoa</strong>\n<strong>BookingCare cung cấp thông tin và lịch khám của các bác sĩ chuyên khoa sản giỏi tại Hà Nội.</strong></p>\n<ul>\n<li>\n<p>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên ngành Sản phụ khoa tại Hà Nội</p>\n</li>\n<li>\n<p>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội như:\nBệnh viện Phụ sản Trung ương, Bệnh viện Phụ sản Hà Nội, Khoa Sản - Bệnh viện Bạch Mai.</p>\n</li>\n</ul>\n<p><strong>Khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Rối loạn kinh nguyệt, chậm kinh, đau bụng kinh</p>\n</li>\n<li>\n<p>Tắc hai vòi trứng, Đa nang buồng trứng, Chụp vòi trứng,</p>\n</li>\n<li>\n<p>Khám hiếm muộn, vô sinh</p>\n</li>\n<li>\n<p>Khám Phụ Khoa</p>\n</li>\n<li>\n<p>Khám thai sản</p>\n</li>\n<li>\n<p>Khám tiền hôn nhân, Tiền sinh</p>\n</li>\n<li>\n<p>Kiểm tra phụ khoa</p>\n</li>\n<li>\n<p>Loạn dưỡng vú</p>\n</li>\n<li>\n<p>Rong kinh kéo dài</p>\n</li>\n<li>\n<p>Siêu âm thai định kỳ</p>\n</li>\n<li>\n<p>Thai lưu</p>\n</li>\n<li>\n<p>U xơ tử cung, Viêm lộ tuyến</p>\n</li>\n</ul>\n', '\n## Sản Phụ khoa\n\n**Bác sĩ Sản phụ khoa**\n**BookingCare cung cấp thông tin và lịch khám của các bác sĩ chuyên khoa sản giỏi tại Hà Nội.**\n\n \n* Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn về chuyên ngành Sản phụ khoa tại Hà Nội\n\n* Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội như:\n Bệnh viện Phụ sản Trung ương, Bệnh viện Phụ sản Hà Nội, Khoa Sản - Bệnh viện Bạch Mai.\n\n**Khám và điều trị**\n\n* Rối loạn kinh nguyệt, chậm kinh, đau bụng kinh\n\n* Tắc hai vòi trứng, Đa nang buồng trứng, Chụp vòi trứng,\n\n	      \n* Khám hiếm muộn, vô sinh\n\n* Khám Phụ Khoa\n\n	   \n* Khám thai sản\n\n \n* Khám tiền hôn nhân, Tiền sinh\n\n	   \n* Kiểm tra phụ khoa\n\n \n* Loạn dưỡng vú\n\n   \n* Rong kinh kéo dài\n\n   \n* Siêu âm thai định kỳ\n\n   \n* Thai lưu\n\n* U xơ tử cung, Viêm lộ tuyến', , '2026-04-05 15:15:44', '2026-04-05 15:15:44');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(17, 'Siêu Âm Thai', '<h2>Siêu âm thai</h2>\n<p><strong>Bác sĩ Siêu âm thai</strong></p>\n<ul>\n<li>\n<p>BookingCare cung cấp thông tin và lịch khám của các bác sĩ chuyên khoa sản - siêu âm thai giỏi tại Hà Nội.</p>\n</li>\n<li>\n<p>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội như: Bệnh viện Phụ sản Trung ương, Bệnh viện Phụ sản Hà Nội, Khoa Sản - Bệnh viện Bạch Mai</p>\n</li>\n</ul>\n<p><strong>Khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Dưới đây là một số vấn đề thường gặp mà các bác sĩ siêu âm thai thường khám và điều trị</p>\n</li>\n<li>\n<p>Khám thai sản</p>\n</li>\n<li>\n<p>Khám thai lần đầu</p>\n</li>\n<li>\n<p>Siêu âm thai định kỳ</p>\n</li>\n<li>\n<p>Siêu âm thai tuần thứ 12</p>\n</li>\n<li>\n<p>Siêu âm thai tuần thứ 16</p>\n</li>\n<li>\n<p>Siêu âm thai tuần thứ 18</p>\n</li>\n<li>\n<p>Siêu âm thai tuần thứ 22</p>\n</li>\n</ul>\n', '\n## Siêu âm thai\n\n**Bác sĩ Siêu âm thai**\n\n* BookingCare cung cấp thông tin và lịch khám của các bác sĩ chuyên khoa sản - siêu âm thai giỏi tại Hà Nội.\n\n* Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội như: Bệnh viện Phụ sản Trung ương, Bệnh viện Phụ sản Hà Nội, Khoa Sản - Bệnh viện Bạch Mai\n\n\n**Khám và điều trị**\n* Dưới đây là một số vấn đề thường gặp mà các bác sĩ siêu âm thai thường khám và điều trị\n\n* Khám thai sản\n\n* Khám thai lần đầu\n\n* Siêu âm thai định kỳ\n\n* Siêu âm thai tuần thứ 12\n\n* Siêu âm thai tuần thứ 16\n\n* Siêu âm thai tuần thứ 18\n\n* Siêu âm thai tuần thứ 22', , '2026-04-05 15:17:51', '2026-04-05 15:17:51');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(18, 'Nhi Khoa', '<h2>Nhi khoa</h2>\n<p>**Bác sĩ chuyên khoa Nhi **\n<strong>Danh sách bác sĩ chuyên khoa Nhi giỏi:</strong></p>\n<ul>\n<li>\n<p>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội</p>\n</li>\n<li>\n<p>Các giảng viên đã và đang trực tiếp nghiên cứu và giảng dạy tại Đại học Y khoa Hà Nội</p>\n</li>\n<li>\n<p>Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như: Bệnh viện Nhi Trung ương, Khoa Nhi - Bệnh viện Bạch Mai.</p>\n</li>\n</ul>\n<p><strong>Khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Bệnh lý sơ sinh</p>\n</li>\n<li>\n<p>Bệnh tiêu hóa</p>\n</li>\n<li>\n<p>Bệnh tuần hoàn</p>\n</li>\n<li>\n<p>Bệnh hô hấp</p>\n</li>\n<li>\n<p>Bệnh huyết học</p>\n</li>\n<li>\n<p>Bệnh thận Tiết niệu</p>\n</li>\n<li>\n<p>Bệnh thần kinh</p>\n</li>\n<li>\n<p>Bệnh ngoài da</p>\n</li>\n<li>\n<p>Bệnh xương khớp</p>\n</li>\n</ul>\n', '\n## Nhi khoa\n\n**Bác sĩ chuyên khoa Nhi **\n**Danh sách bác sĩ chuyên khoa Nhi giỏi:**\n\n* Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội\n\n* Các giảng viên đã và đang trực tiếp nghiên cứu và giảng dạy tại Đại học Y khoa Hà Nội\n\n* Các bác sĩ đã, đang công tác tại các bệnh viện hàng đầu như: Bệnh viện Nhi Trung ương, Khoa Nhi - Bệnh viện Bạch Mai.\n\n**Khám và điều trị**\n\n* Bệnh lý sơ sinh\n\n* Bệnh tiêu hóa\n\n* Bệnh tuần hoàn\n\n* Bệnh hô hấp\n\n* Bệnh huyết học\n\n* Bệnh thận Tiết niệu\n\n* Bệnh thần kinh\n\n* Bệnh ngoài da\n\n* Bệnh xương khớp', , '2026-04-05 15:19:04', '2026-04-05 15:19:04');
INSERT INTO `specialties` (`id`, `name`, `descriptionHTML`, `descriptionMarkdown`, `image`, `createdAt`, `updatedAt`) VALUES
(19, 'Da liễu', '<h2>Da liễu</h2>\n<p><strong>Bác sĩ Chuyên khoa Da liễu</strong>\n<strong>BookingCare cung cấp thông tin và lịch khám của các bác sĩ chuyên khoa da liễu giỏi tại Hà Nội.</strong></p>\n<ul>\n<li>Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội như: Bệnh viện Da liễu Trung ương, Bệnh viện Da liễu Hà Nội</li>\n</ul>\n<p><strong>Khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Bệnh vẩy nến, Da khô, Ngứa da</p>\n</li>\n<li>\n<p>Rám tàn nhang</p>\n</li>\n<li>\n<p>Mụn cóc sinh dục</p>\n</li>\n<li>\n<p>Nấm cơ thể, Nấm da đầu</p>\n</li>\n<li>\n<p>Nấm móng tay, móng chân</p>\n</li>\n<li>\n<p>Rụng tóc, hói đầu</p>\n</li>\n<li>\n<p>Viêm da dị ứng, Viêm da tiếp xúc, Viêm da tiết bã</p>\n</li>\n<li>\n<p>Viêm nang lông</p>\n</li>\n<li>\n<p>Xơ cứng bì</p>\n</li>\n<li>\n<p>Zona thần kinh</p>\n</li>\n</ul>\n', '\n## Da liễu\n\n**Bác sĩ Chuyên khoa Da liễu**\n**BookingCare cung cấp thông tin và lịch khám của các bác sĩ chuyên khoa da liễu giỏi tại Hà Nội.**\n\n* Các chuyên gia có quá trình đào tạo bài bản, kinh nghiệm công tác tại các bệnh viện lớn tại Hà Nội như: Bệnh viện Da liễu Trung ương, Bệnh viện Da liễu Hà Nội\n\n**Khám và điều trị**\n\n* Bệnh vẩy nến, Da khô, Ngứa da\n\n* Rám tàn nhang\n\n* Mụn cóc sinh dục\n\n* Nấm cơ thể, Nấm da đầu\n\n* Nấm móng tay, móng chân\n\n* Rụng tóc, hói đầu\n\n* Viêm da dị ứng, Viêm da tiếp xúc, Viêm da tiết bã\n\n* Viêm nang lông\n\n* Xơ cứng bì\n\n* Zona thần kinh', , '2026-04-05 15:20:35', '2026-04-05 15:20:35');

